min (case when is_secured = 1 then Amount_Past_Due end) as MIN_Amount_Past_Due_secured,
avg (case when is_secured = 1 then Amount_Past_Due end) as AVG_Amount_Past_Due_secured,

sum (case when is_secured = 1 then Current_Balance end) as TOTAL_Current_Balance_secured,
max (case when is_secured = 1 then Current_Balance end) as MAX_Current_Balance_secured,
min (case when is_secured = 1 then Current_Balance end) as MIN_Current_Balance_secured,
avg (case when is_secured = 1 then Current_Balance end) as AVG_Current_Balance_secured,

