max (case when is_unsecured = 1 then Repayment_Tenure end) as MAX_Repayment_Tenure_unsecured,
min (case when is_unsecured = 1 then Repayment_Tenure end) as MIN_Repayment_Tenure_unsecured,
avg (case when is_unsecured = 1 then Repayment_Tenure end) as AVG_Repayment_Tenure_unsecured,

sum (case when is_unsecured = 1 and is_active = 1 then Amount_Past_Due end) as TOTAL_Amount_Past_Due_unsecured_and_active,
