min (case when is_unsecured = 1 and is_closed = 1 then Original_Charge_Off_Amount end) as MIN_Original_Charge_Off_Amount_unsecured_and_closed,
avg (case when is_unsecured = 1 and is_closed = 1 then Original_Charge_Off_Amount end) as AVG_Original_Charge_Off_Amount_unsecured_and_closed,

