FROM
account_details
group by user_id_accounts,bre_run_id_accounts, id_accounts
)
-- select * from account_details_features
,
dpd as
(
select
a.USER_ID as dpd_user_id,
a.bre_run_id as dpd_bre_run_id,
a.id as dpd_id,
a.reference_date,
a.Account_Number,
a.is_Active,
a.is_Closed,
a.is_Secured,
a.is_Unsecured,
a.Age_of_Account_days,
a.days_since_account_closing,
a.days_since_last_reporting,
a.days_since_last_payment,
try_cast(replace(replace(f.value:Days_Past_Due,'"',''),'"','') as INTEGER) as Days_Past_Due,
try_cast(replace(f.value:Month,'"','')as INTEGER) as Month,
try_cast(replace(f.value:Year,'"','')as INTEGER) as Year,
date_from_parts(Year, Month,1) as dpd_date,
reference_date - dpd_date as days_from_dpd
FROM
(
SELECT
user_id,
bre_run_id,
id,
reference_date,
Account_Number,
CAIS_Account_History,
is_Active,
is_Closed,
is_Secured,
is_Unsecured,
Age_of_Account_days,
days_since_account_closing,
days_since_last_reporting,
days_since_last_payment
FROM
account_details) a,
lateral flatten(input => a.CAIS_Account_History) f
)
