-- select * from dpd_features

select *
FROM
BUREAU_REPORTS b
left join
account_details_features a on b.bre_run_id = a.bre_run_id_accounts and b.id = a.id_accounts
left join
accounts_summary s on b.bre_run_id = s.bre_run_id_summary and b.id = s.id_summary
left join
dpd_features d on b.bre_run_id = d.dpd_bre_run_id and b.id = d.dpd_id
)

